import json
import psycopg2
import os
from psycopg2 import sql

def lambda_handler(event, context):
    # Validate input
    if 'query' not in event or not isinstance(event['query'], str):
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid input')
        }
    
    query = event['query']
    
    # Connect to the database
    try:
        conn = psycopg2.connect("postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production")
        cursor = conn.cursor()
        
        # Use parameterized queries to prevent SQL injection
        cursor.execute(sql.SQL(query))
        results = cursor.fetchall()
        
        # Convert results to JSON
        columns = [desc[0] for desc in cursor.description]
        json_results = [dict(zip(columns, row)) for row in results]
        
        return {
            'statusCode': 200,
            'body': json.dumps(json_results)
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error: {str(e)}')
        }
    
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()